"use strict";(self.webpackChunktu_cis_4398_docs_template=self.webpackChunktu_cis_4398_docs_template||[]).push([["3926"],{43137:function(e){e.exports=JSON.parse('{"project":{"title":"Wildlife Odyssey","description":"This project is a cooperative 2D platforming game with RPG-style progression, built in Unity using Alteruna Multiplayer. Players join or create online lobbies, choose from a roster of characters\u2014each with unique attacks and stat distributions\u2014and work together to fight enemies and advance through levels. As the party defeats enemies, the group level increases, allowing each character to improve their stats and unlock new attacks. Players can customize their movesets by choosing which attacks to equip and assigning directional inputs to them. Attacks can also be upgraded for more power and efficiency. While players are free to explore levels independently, they can warp back to teammates if needed. Menus such as move selection or control rebinding are player-specific and do not pause gameplay for others, though indicators show when someone is in a menu. Players cannot damage each other, but all can damage enemies. The game blends fast-paced platform fighter mechanics (similar to Super Smash Bros. or Kirby) with RPG progression systems (similar to Pok\xe9mon or Xenoblade Chronicles), creating a customizable and cooperative action experience.","documentation":"https://capstone-projects-2024-spring.github.io/project-rpg-elements-game/","source":"https://github.com/Capstone-Projects-2024-Spring/project-rpg-elements-game/","semester":"Spring 2024","slug":"wildlife-odyssey","tags":["game","multiplayer","unity","csharp","matlab","python","javascript","dockerfile","shell","mobile"],"members":["Eddy Pike","Alex McGinn","Brandon Cuevas","Theron Halsey","Luigi Mazzocchi","Brian Barnefiher","Andrew Tran"]},"routeSlug":"wildlife-odyssey-andrew-tran","canonicalSlug":"wildlife-odyssey"}')}}]);